import { setPaymentMethod } from '@/checkout/api';
import { PaymentMethods as PaymentMethodsComponent } from '@/checkout/components/PaymentMethods/PaymentMethods';
import { Cart } from '@/checkout/data/models/cart';
import {
  AdditionalData,
  PaymentMethod
} from '@/checkout/data/models/payment-method';
import { NegotiableQuote } from '@/checkout/data/models/quote';
import {
  getLatestCheckoutUpdate,
  getValue,
  hasPendingUpdates,
  hasShippingAddress,
  notifyValues,
  state
} from '@/checkout/lib';
import { isVirtualCart } from '@/checkout/lib/utils/events';
import { TitleProps, UIComponentType } from '@/checkout/types';
import { useText } from '@adobe-commerce/elsie/i18n';
import {
  Container,
  deepmerge,
  Slot,
  SlotProps
} from '@adobe-commerce/elsie/lib';
import { events } from '@adobe-commerce/event-bus';
import { HTMLAttributes } from 'preact/compat';
import { useCallback, useEffect, useMemo, useState } from 'preact/hooks';
import { defaultHandlers } from './handlers';

interface RenderContext {
  additionalData?: AdditionalData;
  cartId: string;
  replaceHTML: (domElement: HTMLElement) => void;
  setAdditionalData: (data: AdditionalData) => void;
}

export interface PaymentMethodConfig {
  autoSync?: boolean;
  displayLabel?: boolean;
  enabled?: boolean;
  icon?: string;
  render?: SlotProps<RenderContext>;
}

export interface PaymentMethodHandlers {
  [code: string]: PaymentMethodConfig;
}

interface CartSyncError {
  method: PaymentMethod;
  error: Error;
}

export interface PaymentMethodsProps
  extends HTMLAttributes<HTMLDivElement>,
  TitleProps {
  slots?: {
    Methods?: PaymentMethodHandlers;
  } & TitleProps['slots'];
  UIComponentType?: UIComponentType;
  active?: boolean;
  autoSync?: boolean;
  onCartSyncError?: (error: CartSyncError) => void;
  onSelectionChange?: (method: PaymentMethod) => void;
}

function isAvailable(
  selection: PaymentMethod | null,
  options: PaymentMethod[]
) {
  if (!selection) return false;
  return options.some((option) => option.code === selection.code);
}

function isEqual(a: PaymentMethod | null, b: PaymentMethod | null) {
  if (!a || !b) return false;
  return a.code === b.code;
}

function isValid(method: PaymentMethod | null) {
  if (!method) return false;
  return !!method.code && !!method.title;
}

export const PaymentMethods: Container<PaymentMethodsProps> = ({
  UIComponentType = 'ToggleButton',
  active = true,
  autoSync = true,
  displayTitle = true,
  slots,
  onCartSyncError,
  onSelectionChange,
}) => {
  const [error, setError] = useState<string | null>(null);
  const [isInitialized, setIsInitialized] = useState(false);
  const [selection, setSelection] = useState<PaymentMethod | null>(null);
  const [options, setOptions] = useState<PaymentMethod[]>([]);
  const isBusy = hasPendingUpdates.value;

  const { cartSyncError, defaultTitle } = useText({
    cartSyncError: 'Checkout.PaymentMethods.cartSyncError',
    defaultTitle: 'Checkout.PaymentMethods.title',
  });

  const availableHandlers = useMemo(() => {
    const customHandlers = slots?.Methods ?? {};
    return deepmerge(defaultHandlers, customHandlers);
  }, [slots?.Methods]);

  const getSlot = useCallback((method: PaymentMethod) => {
    return availableHandlers[method.code]?.render;
  }, [availableHandlers]);

  const hasAutoSyncEnabled = useCallback((method: PaymentMethod) => {
    const config = availableHandlers[method.code];
    if (!config) return autoSync;
    return config.autoSync !== false;
  }, [autoSync, availableHandlers]);

  const isEnabled = useCallback((method: PaymentMethod) => {
    const config = availableHandlers[method.code]?.enabled;
    return config !== false;
  }, [availableHandlers]);

  const withIcons = useCallback((options: PaymentMethod[]) => {
    return options.map((option) => {
      const handler = availableHandlers[option.code];
      if (!handler) return option;
      return {
        ...option,
        icon: handler.icon
      };
    });
  }, [availableHandlers]);

  const setAdditionalData = useCallback((additionalData: AdditionalData) => {
    setSelection((prev) => {
      if (!prev) return prev;
      return { ...prev, additionalData };
    });
  }, []);

  const handleDismissError = useCallback(() => {
    setError(null);
  }, []);

  const updateSelection = useCallback((selection: PaymentMethod | null) => {
    setError(null);
    setSelection(selection);
  }, []);

  const updateCartSelection = useCallback(
    async (selection: PaymentMethod, fallback?: PaymentMethod | null) => {
      const canSetSelectionOnCart = isVirtualCart() || hasShippingAddress();

      if (!canSetSelectionOnCart) return;
      if (!hasAutoSyncEnabled(selection)) return;

      setPaymentMethod({
        code: selection.code,
        ...(selection.additionalData ?? {}),
      }).catch((error) => {
        updateSelection(fallback ?? null);
        setError(onCartSyncError ? null : cartSyncError);
        onCartSyncError?.({ method: selection, error });
      });
    },
    [
      cartSyncError,
      hasAutoSyncEnabled,
      onCartSyncError,
      updateSelection,
    ]
  );

  const handleSelectionChange = useCallback(
    async (selection: PaymentMethod) => {
      const prevSelection = getValue('selectedPaymentMethod');
      updateSelection(selection);
      onSelectionChange?.(selection);
      await updateCartSelection(selection, prevSelection);
    },
    [onSelectionChange, updateSelection, updateCartSelection]
  );

  const handleCheckoutData = useCallback(
    (data: Cart | NegotiableQuote | null) => {
      const isEmptyCart = !data || data.isEmpty;

      if (isEmptyCart) {
        updateSelection(null);
        setOptions([]);
        return;
      }

      const availableOptions = data.availablePaymentMethods ?? [];
      const enabledOptions = availableOptions.filter(isEnabled);

      setOptions(enabledOptions);

      if (enabledOptions.length === 0) {
        updateSelection(null);
        return;
      }

      const cartSelection = data.selectedPaymentMethod ?? null;
      const hasCartSelection = isValid(cartSelection);
      const userSelection = getValue('selectedPaymentMethod');
      const isUserSelectionAvailable = isAvailable(userSelection, enabledOptions);
      const haveSameSelection = isEqual(userSelection, cartSelection);

      // User has valid selection that differs from cart
      if (userSelection && isUserSelectionAvailable && !haveSameSelection) {
        updateCartSelection(userSelection, cartSelection);
        return;
      }

      // User has invalid selection but cart has valid selection
      if (
        (!userSelection || !isUserSelectionAvailable) &&
        hasCartSelection &&
        isAvailable(cartSelection, enabledOptions)
      ) {
        updateSelection(cartSelection);
        return;
      }

      // Neither user nor cart has valid selection (or both selections are unavailable)
      if (
        (!userSelection || !isUserSelectionAvailable) &&
        (!hasCartSelection ||
          !isAvailable(cartSelection, enabledOptions))
      ) {
        const newSelection = enabledOptions[0];
        updateSelection(newSelection);
        updateCartSelection(newSelection);
      }
    },
    [isEnabled, updateSelection, updateCartSelection]
  );

  useEffect(() => {
    if (!active) return;

    const pastUpdate = getLatestCheckoutUpdate();

    if (pastUpdate) {
      setIsInitialized(true);
      // When component becomes active, restore key state so handleCheckoutData can work properly
      const userSelection = getValue('selectedPaymentMethod');
      if (userSelection) {
        setSelection(userSelection);
      }
      handleCheckoutData(pastUpdate);
      return;
    }

    const onCheckoutInit = events.on(
      'checkout/initialized',
      (data: Cart | NegotiableQuote | null) => {
        setIsInitialized(true);
        handleCheckoutData(data);
      },
      { eager: true }
    );

    return () => {
      onCheckoutInit?.off();
    };
  }, [active, handleCheckoutData]);

  useEffect(() => {
    if (!active) return;

    const onCheckoutUpdated = events.on(
      'checkout/updated',
      handleCheckoutData,
      { eager: false }
    );

    return () => {
      onCheckoutUpdated?.off();
    };
  }, [active, handleCheckoutData]);

  useEffect(() => {
    notifyValues({ selectedPaymentMethod: selection });
  }, [selection]);

  const titleContent = useMemo(() => {
    if (!displayTitle) return undefined;

    return (
      <Slot name="checkout-payment-methods-title" slot={slots?.Title}>
        <h2>{defaultTitle}</h2>
      </Slot>
    );
  }, [displayTitle, slots?.Title, defaultTitle]);

  const paymentMethodContent = useMemo(() => {
    if (!selection) return;

    const slot = getSlot(selection);
    if (!slot) return;

    return (
      <Slot
        key={selection!.code}
        context={{
          additionalData: selection!.additionalData,
          cartId: state.cartId ?? '',
          replaceHTML(domElement: HTMLElement) {
            this.replaceWith(domElement);
          },
          setAdditionalData,
        }}
        name="PaymentMethodContent"
        slot={slot}
      />
    );

  }, [getSlot, selection, setAdditionalData]);

  return (
    <PaymentMethodsComponent
      UIComponentType={UIComponentType}
      busy={isBusy}
      error={error}
      initialized={isInitialized}
      options={withIcons(options)}
      paymentMethodContent={paymentMethodContent}
      selection={selection}
      title={titleContent}
      visible={active}
      onDismissError={handleDismissError}
      onSelectionChange={handleSelectionChange}
    />
  );
};
