import { setPaymentMethod } from '@/checkout/api';
import {
  PaymentMethodConfig,
  PaymentOnAccount,
  PurchaseOrder,
} from '@/checkout/containers';
import { validateNotEmpty } from '@/checkout/lib/validation';
import { render as Checkout } from '@/checkout/render/render';
import { Container } from '@adobe-commerce/elsie/lib';
import { debounce } from '@adobe-commerce/elsie/lib/debounce';

interface HandlerConfig {
  Container: Container<any>;
  autoSync: boolean;
  formName?: string;
  validateRefNumber: boolean;
}

export enum HandlerCode {
  PaymentOnAccount = 'companycredit',
  PurchaseOrder = 'purchaseorder',
}

const HANDLERS_CONFIG: Record<HandlerCode, HandlerConfig> = {
  [HandlerCode.PaymentOnAccount]: {
    Container: PaymentOnAccount,
    autoSync: true,
    formName: 'payment-on-account',
    validateRefNumber: false,
  },
  [HandlerCode.PurchaseOrder]: {
    Container: PurchaseOrder,
    autoSync: false,
    formName: 'purchase-order',
    validateRefNumber: true,
  },
} as const;

// Cache for debounced handlers to prevent memory leaks
const debouncedHandlers = new Map<string, ReturnType<typeof debounce>>();

export const handleRefNumberChange = (code: string, isRequired: boolean) => {
  const key = `${code}-${isRequired}`;

  if (!debouncedHandlers.has(key)) {
    const debouncedFn = debounce(async (refNumber: string) => {
      if (!isRequired || validateNotEmpty(refNumber)) {
        try {
          await setPaymentMethod({
            code,
            purchase_order_number: refNumber,
          });
        } catch (error) {
          console.error(`Failed to set payment method for ${code}:`, error);
        }
      }
    }, 1000);

    debouncedHandlers.set(key, debouncedFn);
  }

  return debouncedHandlers.get(key)!;
};

const handlerCache: Partial<Record<HandlerCode, PaymentMethodConfig>> = {};

export const resetHandlersCache = () => {
  Object.keys(handlerCache).forEach((key) => {
    delete handlerCache[key as HandlerCode];
  });

  debouncedHandlers.clear();
};

export const createHandler = (code: HandlerCode): PaymentMethodConfig => {
  if (!(code in HANDLERS_CONFIG)) {
    throw new Error(`Invalid handler code: ${code}`);
  }

  if (handlerCache[code]) {
    return handlerCache[code] as PaymentMethodConfig;
  }

  const config = HANDLERS_CONFIG[code];

  const { autoSync, Container, formName, validateRefNumber } = config;

  const handler: PaymentMethodConfig = {
    enabled: true,
    autoSync,
    render: (ctx) => {
      const initialReferenceNumber = String(
        ctx.additionalData?.purchase_order_number ?? ''
      );

      const $wrapper = document.createElement('div');

      Checkout.render(Container, {
        name: formName,
        initialReferenceNumber,
        onReferenceNumberChange: handleRefNumberChange(code, validateRefNumber),
      })($wrapper);

      ctx.replaceHTML($wrapper);
    },
  };

  handlerCache[code] = handler;

  return handler;
};

export const defaultHandlers = {
  [HandlerCode.PaymentOnAccount]: createHandler(HandlerCode.PaymentOnAccount),
  [HandlerCode.PurchaseOrder]: createHandler(HandlerCode.PurchaseOrder),
};
